const OPENAI_GENRE_FALLBACK = { genreId: "learning", subgenreId: "knowledge-mgmt" };

function getOpenAiGenreById(genreId) {
  return OPENAI_GENRE_TAXONOMY.find((g) => g.id === genreId) || null;
}

function getOpenAiSubgenreEntry(genreId, subgenreId) {
  const genre = getOpenAiGenreById(genreId);
  if (!genre) return null;
  return genre.subgenres.find((s) => s.id === subgenreId) || null;
}

function resolveOpenAiSubgenreEntry(genreId, subgenreId) {
  const found = getOpenAiSubgenreEntry(genreId, subgenreId);
  if (found) return { genre: getOpenAiGenreById(genreId), subgenre: found };
  const fb = getOpenAiSubgenreEntry(
    OPENAI_GENRE_FALLBACK.genreId,
    OPENAI_GENRE_FALLBACK.subgenreId
  );
  return {
    genre: getOpenAiGenreById(OPENAI_GENRE_FALLBACK.genreId),
    subgenre: fb
  };
}

const OPENAI_AI_ACTION_DEEP_DIVE = "deep-dive";
const OPENAI_AI_ACTION_SIMPLE_LIST = "simple-list";

const OPENAI_DEEP_DIVE_SCRIPT_PREAMBLE = `出力モード: 深く調べる
- 情報を圧縮・省略・言い換えで薄めない。調査・解説レポートとして厚く書く
- 各節は指示の下限以上を目安に、根拠・具体例・条件・反例・未確定点まで書く
- 「要約」節は全体の代用品にしない。背景・前提・争点・複数視点・根拠の強弱・未解決の疑問を後続節で必ず扱う
- 箇条書きだけで済ませず、段落の説明文を厚くする
- 推測と事実を明確に区別する`;

function isOpenAiDeepDiveAction(actionId) {
  return String(actionId || "").trim() === OPENAI_AI_ACTION_DEEP_DIVE;
}

function isOpenAiSimpleListAction(actionId) {
  return String(actionId || "").trim() === OPENAI_AI_ACTION_SIMPLE_LIST;
}

function amplifyDeepDiveNumericRanges(text) {
  return String(text || "").replace(/(\d+)〜(\d+)/g, (_, lo, hi) => {
    const lower = parseInt(lo, 10);
    const upper = parseInt(hi, 10);
    const nextLo = Math.min(Math.max(lower + 2, lower * 2), 20);
    const nextHi = Math.min(Math.max(upper + 3, upper * 2), 24);
    return `${Math.min(nextLo, nextHi)}〜${Math.max(nextLo, nextHi)}`;
  });
}

const DEEP_DIVE_SUMMARY_TITLES = new Set(["要約", "調査目的", "研究概要", "概要"]);

function adaptOpenAiSectionForDeepDive(section) {
  const title = String(section.title || "");
  let instruction = String(section.instruction || "");

  if (DEEP_DIVE_SUMMARY_TITLES.has(title)) {
    instruction =
      "全体の圧縮要約は禁止。ここは導線のみ：対象・調査目的・読者が得る見取り図を5〜7文。"
      + "詳細・根拠・事例・争点は後続の節に必ず展開すること";
  } else if (title === "一言でいうと") {
    instruction = "1〜2文。後続の深掘り内容を否定するほど単純化しない";
  } else if (title === "ポイント") {
    instruction =
      `${amplifyDeepDiveNumericRanges(instruction)}。`
      + "できる限り原文を厚く blockquote で引用し、要約で置き換えない";
  } else if (title === "未来予想") {
    instruction =
      `${amplifyDeepDiveNumericRanges(instruction)}。`
      + "短期/中期/長期の時間軸・複数シナリオ・根拠の強弱・実現可能性・リスクも厚く書く";
  } else {
    instruction = amplifyDeepDiveNumericRanges(instruction);
    if (/文/.test(instruction) && !/\d+〜\d+文/.test(instruction)) {
      instruction += "。各要点は段落で厚く説明する";
    }
  }

  return { title, instruction };
}

const COMPACT_DROP_TITLES = new Set(["要約", "一言でいうと", "調査目的", "研究概要", "概要"]);

function resolveOpenAiSubgenreSectionList(subgenre, compact) {
  const source = compact && Array.isArray(subgenre.compactSections) && subgenre.compactSections.length
    ? subgenre.compactSections
    : (subgenre.sections || []);
  if (!compact) return source;
  return source.filter((section) => !COMPACT_DROP_TITLES.has(String(section.title || "")));
}

const OPENAI_STANDARD_SCRIPT_PREAMBLE = `出力スタイル: 解説ノート（標準）
- 入力の事実・意図を正確に反映する。創作・一般論・未来予測で穴埋めしない
- 各節は内容に見合った長さにする。根拠のない節は省略してよい
- 比較・手順があるときだけ表や箇条書きを使う
- 引用は入力に明確な該当がある場合のみ blockquote で（創作引用禁止）
- 末尾に「確信度：高/中/低」と1文の所見を付ける（入力不足なら「低」）`;

const OPENAI_COMPACT_SCRIPT_PREAMBLE = `出力スタイル: 実用メモ向け（簡潔リスト）
- 箇条書き・表中心。各項目は1行を基本とする
- 冗長な説明・まとめ段落・「要約」「一言でいうと」的な締めは不要
- 導入段落も不要。指定見出しから直接始める`;

function formatOpenAiSubgenreSections(subgenre, options = {}) {
  const deepDive = isOpenAiDeepDiveAction(options.actionId);
  const compact = isOpenAiSimpleListAction(options.actionId);
  const intro = deepDive
    ? "（導入段落・見出しなし）\n- 背景・文脈・なぜ今これが重要かを3〜5文。ここだけで全体を要約しない"
    : compact
      ? "（導入段落不要）\n- 前置き・要約・まとめは書かず、指定見出しから直接始める"
      : "（導入段落・見出しなし）\n- この内容が何についてのものかを1〜2文。複数概念の関係があれば対比で一言述べる";
  const sections = resolveOpenAiSubgenreSectionList(subgenre, compact).map((section) =>
    deepDive ? adaptOpenAiSectionForDeepDive(section) : section
  );
  const blocks = sections.map((section) => {
    const heading = section.title.startsWith("（") ? section.title : `## ${section.title}`;
    const lines = String(section.instruction || "")
      .split(/[。\n]/)
      .map((s) => s.trim())
      .filter(Boolean);
    const bullets = lines.length
      ? lines.map((line) => `- ${line.endsWith("。") ? line : line + "。"}`).join("\n")
      : `- ${section.instruction}`;
    if (heading.startsWith("（")) {
      return `${heading}\n${bullets}`;
    }
    return `${heading}\n${bullets}`;
  });
  return [intro, ...blocks].join("\n\n");
}

function buildOpenAiSubgenreScriptMarkdown(genre, subgenre, options = {}) {
  const deepDive = isOpenAiDeepDiveAction(options.actionId);
  const compact = isOpenAiSimpleListAction(options.actionId);
  const scene = subgenre.scene || "";
  const sections = formatOpenAiSubgenreSections(subgenre, options);
  const modeBlock = deepDive
    ? `${OPENAI_DEEP_DIVE_SCRIPT_PREAMBLE}\n\n`
    : compact
      ? `${OPENAI_COMPACT_SCRIPT_PREAMBLE}\n\n`
      : `${OPENAI_STANDARD_SCRIPT_PREAMBLE}\n\n`;
  return `${modeBlock}利用シーン: ${scene}\nジャンル: ${genre.label} / ${subgenre.label}\n\n出力構成（この順序・意味を厳守。## 見出しは {{OUTPUT_LANGUAGE}} に自然な表現へ翻訳）:\n\n${sections}`;
}

function buildOpenAiGenreCatalogForClassification() {
  return OPENAI_GENRE_TAXONOMY.map((genre) => {
    const subs = genre.subgenres
      .map((s) => `  - ${s.id}: ${s.label}（${s.scene}）`)
      .join("\n");
    return `- ${genre.id}: ${genre.label} — ${genre.description}\n${subs}`;
  }).join("\n\n");
}

function parseOpenAiGenreClassification(raw) {
  const text = String(raw || "").trim();
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) return { ...OPENAI_GENRE_FALLBACK, confidence: 0, reason: "" };
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    const genreId = String(parsed.genreId || parsed.genre || "").trim();
    const subgenreId = String(parsed.subgenreId || parsed.subgenre || "").trim();
    if (getOpenAiSubgenreEntry(genreId, subgenreId)) {
      return {
        genreId,
        subgenreId,
        confidence: Number(parsed.confidence) || 0,
        reason: String(parsed.reason || "").trim()
      };
    }
  } catch (_) {
    /* fall through */
  }
  return { ...OPENAI_GENRE_FALLBACK, confidence: 0, reason: "" };
}
